import ifcopenshell.geom
from core.logger import setup_logger

logger = setup_logger(__name__)

class GeometryDetector:
    """
    Detecteert of een element geometrie-representatie heeft.
    TRUE = minstens één eigenschap is aanwezig (shape, representation, etc.)
    """

    def __init__(self, ifc_file):
        self.ifc_file = ifc_file

    def has_geometric_representation(self, element):
        """
        Controleer of een element geometrische representatie heeft.

        Args:
            element: IFC-element object

        Returns:
            bool: True als minstens één geometrische eigenschap aanwezig is
        """
        try:
            # Methode 1: Controleer op IFCPRODUCTDEFINITIONSHAPE
            if self._has_product_definition_shape(element):
                return True

            # Methode 2: Controleer op IFCSHAPEREPRESENTATION
            if self._has_shape_representation(element):
                return True

            # Methode 3: Probeer 3D-geometrie via ifcopenshell.geom
            if self._can_generate_geometry(element):
                return True

            return False

        except Exception as e:
            logger.debug(f"Fout bij geometrie-detectie voor element {element.id()}: {e}")
            return False

    def _has_product_definition_shape(self, element):
        """
        Controleer of element IFCPRODUCTDEFINITIONSHAPE heeft.
        """
        try:
            if hasattr(element, 'Representation'):
                if element.Representation is not None:
                    if element.Representation.is_a('IFCPRODUCTDEFINITIONSHAPE'):
                        return True
        except Exception as e:
            logger.debug(f"_has_product_definition_shape fout: {e}")

        return False

    def _has_shape_representation(self, element):
        """
        Controleer of element IFCSHAPEREPRESENTATION heeft via Representation.
        """
        try:
            if hasattr(element, 'Representation'):
                if element.Representation is not None:
                    if hasattr(element.Representation, 'Representations'):
                        representations = element.Representation.Representations
                        if representations and len(representations) > 0:
                            for rep in representations:
                                if rep.is_a('IFCSHAPEREPRESENTATION'):
                                    return True
        except Exception as e:
            logger.debug(f"_has_shape_representation fout: {e}")

        return False

    def _can_generate_geometry(self, element):
        """
        Probeer daadwerkelijk geometrie te genereren via ifcopenshell.geom.
        Dit is de minst betrouwbare methode maar most fallback.
        """
        try:
            settings = ifcopenshell.geom.settings()
            settings.set(settings.DISABLE_OPENING_SUBTRACTION, False)

            shape = ifcopenshell.geom.create_shape(settings, element)

            if shape is not None:
                # Controleer of shape daadwerkelijk inhoud heeft
                verts = shape.verts
                if verts and len(verts) > 0:
                    return True

        except Exception as e:
            logger.debug(f"_can_generate_geometry fout: {e}")

        return False

from core.logger import setup_logger

logger = setup_logger(__name__)

class TypeLinker:
    """
    Koppelt elementen aan hun TYPE-definities en haalt type-informatie op.
    """

    def __init__(self, ifc_file):
        self.ifc_file = ifc_file
        self.type_cache = {}  # Cache voor sneller opzoeken

    def get_type_link_and_name(self, element):
        """
        Haal TYPE-relatie en type-naam op van een element.

        Args:
            element: IFC-element object

        Returns:
            tuple: (type_link_id, type_name) of (None, None)
        """
        try:
            # Controleer of element TYPE-relatie heeft
            type_obj = self._get_type_object(element)

            if type_obj is None:
                return None, None

            type_id = type_obj.id()
            type_name = self._get_type_name(type_obj)

            return type_id, type_name

        except Exception as e:
            logger.debug(f"Fout bij type-linking voor element {element.id()}: {e}")
            return None, None

    def _get_type_object(self, element):
        """
        Haal het TYPE-object op van een element.
        Zoekt via IFCRELDEFINESBYTYPE relatie.
        """
        try:
            # Check cache eerst
            element_id = element.id()
            if element_id in self.type_cache:
                return self.type_cache[element_id]

            # Methode 1: Direct via IsDefinedBy
            if hasattr(element, 'IsDefinedBy'):
                for rel in element.IsDefinedBy:
                    if rel.is_a('IFCRELDEFINESBYTYPE'):
                        if hasattr(rel, 'RelatingType'):
                            type_obj = rel.RelatingType
                            self.type_cache[element_id] = type_obj
                            return type_obj

            # Methode 2: Via RelatedObjects (inverse relatie)
            related_objects = self.ifc_file.by_type('IFCRELDEFINESBYTYPE')
            for rel in related_objects:
                if hasattr(rel, 'RelatedObjects'):
                    if element in rel.RelatedObjects:
                        if hasattr(rel, 'RelatingType'):
                            type_obj = rel.RelatingType
                            self.type_cache[element_id] = type_obj
                            return type_obj

            self.type_cache[element_id] = None
            return None

        except Exception as e:
            logger.debug(f"_get_type_object fout: {e}")
            return None

    def _get_type_name(self, type_obj):
        """
        Haal de naam van het TYPE-object op.
        Fallback: gebruik klassenaam als Name ontbreekt.
        """
        try:
            if hasattr(type_obj, 'Name') and type_obj.Name:
                return type_obj.Name
            else:
                # Fallback: klassennaam
                return type_obj.is_a()

        except Exception as e:
            logger.debug(f"_get_type_name fout: {e}")
            return type_obj.is_a() if type_obj else "UNKNOWN"
